inputs.script:
const p = window.__rzn_params || {};
const norm = (s) => (s || '').replace(/ /g, ' ').replace(/\s+/g, ' ').trim();
const fmt = norm(p.format).toLowerCase();
let lim = parseInt(p.limit, 10);
if (!Number.isFinite(lim) || lim < 1) lim = 25;
if (lim > 100) lim = 100;
const origin = location.origin;
const abs = (h) => { if (!h) return ''; try { return new URL(h, origin).href; } catch (e) { return ''; } };
const md5re = /md5=([a-fA-F0-9]{32})/;
const t = document.querySelector('#tablelibgen');
if (!t) {
  return { layout_ok: false, error: 'No #tablelibgen results table on this page. base_url may not be a libgen.li-family mirror.', query: norm(p.query) || null, format: fmt || null, count: 0, results: [] };
}
const rows = Array.from(t.querySelectorAll('tbody tr'));
const out = [];
for (const r of rows) {
  const c = r.children;
  if (c.length < 9) continue;
  const titleA = c[0].querySelector('a[href*="edition.php"]') || c[0].querySelector('a[href*="file.php"]') || c[0].querySelector('a');
  const title = norm(titleA ? titleA.textContent : c[0].textContent);
  if (!title) continue;
  const ext = norm(c[7].textContent).toLowerCase();
  if (fmt && ext !== fmt) continue;
  let md5 = '';
  for (const a of Array.from(c[8].querySelectorAll('a'))) {
    const m = (a.getAttribute('href') || '').match(md5re);
    if (m) { md5 = m[1].toLowerCase(); break; }
  }
  const edA = c[0].querySelector('a[href*="edition.php"]');
  const flA = c[6].querySelector('a[href*="file.php"]');
  out.push({
    title: title,
    author: norm(c[1].textContent),
    publisher: norm(c[2].textContent),
    year: norm(c[3].textContent),
    language: norm(c[4].textContent),
    pages: norm(c[5].textContent),
    size: norm(c[6].textContent),
    ext: ext,
    md5: md5,
    edition_url: abs(edA ? edA.getAttribute('href') : ''),
    file_url: abs(flA ? flA.getAttribute('href') : '')
  });
  if (out.length >= lim) break;
}
return { layout_ok: true, query: norm(p.query) || null, format: fmt || null, count: out.length, results: out };
